<template><a-card :bordered="false"><a-spin :spinning="loading"><a-row :gutter="16"><a-col :span="6"><a-card :bodyStyle="{padding:'16px'}"><div class="stat-num">{{ stats.total||0 }}</div><div class="stat-label">总内容数</div></a-card></a-col><a-col :span="6"><a-card :bodyStyle="{padding:'16px'}"><div class="stat-num">{{ stats.published||0 }}</div><div class="stat-label">已发布</div></a-card></a-col><a-col :span="6"><a-card :bodyStyle="{padding:'16px'}"><div class="stat-num">{{ (stats.views||0).toLocaleString() }}</div><div class="stat-label">总阅读量</div></a-card></a-col><a-col :span="6"><a-card :bodyStyle="{padding:'16px'}"><div class="stat-num">{{ stats.inquiries||0 }}</div><div class="stat-label">带来询盘</div></a-card></a-col></a-row><a-row :gutter="16" style="margin-top:16px"><a-col :span="12"><a-card title="按格式统计" size="small"><a-table :dataSource="stats.by_format||[]" :pagination="false" size="small" rowKey="format"><a-table-column title="格式" dataIndex="format"><template slot-scope="t">{{ ({long:'长文',video:'视频',social:'朋友圈',seo:'SEO'})[t] }}</template></a-table-column><a-table-column title="数量" dataIndex="cnt" width="80"/><a-table-column title="阅读" dataIndex="v" width="100"/><a-table-column title="询盘" dataIndex="iq" width="80"/></a-table></a-card></a-col><a-col :span="12"><a-card title="高阅读 TOP10" size="small"><a-table :dataSource="stats.top_viewed||[]" :pagination="false" size="small" rowKey="id"><a-table-column title="标题" dataIndex="title" ellipsis/><a-table-column title="阅读" dataIndex="views" width="80"/></a-table></a-card></a-col></a-row><a-card title="近30天趋势" size="small" style="margin-top:16px"><div class="trend-bar"><div v-for="t in trend" :key="t.d" class="trend-col"><div class="trend-bar-inner" :style="{height:barH(t.cnt)+'px'}"><span>{{ t.cnt }}</span></div><div class="trend-date">{{ t.d.slice(5) }}</div></div></div></a-card></a-spin></a-card></template>
<script>import { getStats } from '@skills/contentengine/views/content';export default { name:'ContentAnalytics',data(){return{loading:false,stats:{}}},computed:{trend(){return this.stats.trend||[]},maxCnt(){return Math.max(1,...this.trend.map(t=>t.cnt)||[1])}},created(){this.loadStats()},methods:{loadStats(){this.loading=true;getStats().then(res=>{this.stats=res.data||{}}).finally(()=>{this.loading=false})},barH(cnt){return Math.max(4,cnt/this.maxCnt*120)}}}</script>
<style scoped>.stat-num{font-size:28px;font-weight:bold;color:#d6893b}.stat-label{font-size:12px;color:#999;margin-top:4px}.trend-bar{display:flex;align-items:flex-end;gap:2px;height:140px;padding-top:10px}.trend-col{flex:1;display:flex;flex-direction:column;align-items:center;justify-content:flex-end;height:100%}.trend-bar-inner{width:100%;background:#d6893b;border-radius:2px 2px 0 0;min-width:12px;display:flex;align-items:flex-end;justify-content:center}.trend-bar-inner span{font-size:10px;color:#fff;padding:1px 0}.trend-date{font-size:10px;color:#999;margin-top:2px}</style>
